public class OutputTextTag extends UIComponentTag { private String converter ; private String value ; private String escape ; private String style ; private String styleClass ; private String title ; public void setConverter ( String converter ) { this . converter = converter ; } public void setValue ( String value ) { this . value = value ; } public void setEscape ( String escape ) { this . escape = escape ; } public void setStyle ( String style ) { this . style = style ; } public void setStyleClass ( String styleClass ) { this . styleClass = styleClass ; } public void setTitle ( String title ) { this . title = title ; } public String getRendererType ( ) { return "javax.faces.Text" ; } public String getComponentType ( ) { return "javax.faces.HtmlOutputText" ; } protected void setProperties ( UIComponent component ) { super . setProperties ( component ) ; UIOutput output ; try { output = ( UIOutput ) component ; } catch ( ClassCastException cce ) { throw new FacesException ( "Tag <" + getClass ( ) . getName ( ) + "> expected UIOutput. " + "Got <" + component . getClass ( ) . getName ( ) + ">" ) ; } if ( converter != null ) { if ( FacesUtils . isExpression ( converter ) ) { output . setValueBinding ( "converter" , createValueBinding ( converter ) ) ; } else { output . setConverter ( getApplication ( ) . createConverter ( converter ) ) ; } } if ( value != null ) { if ( FacesUtils . isExpression ( value ) ) { output . setValueBinding ( "value" , createValueBinding ( value ) ) ; } else { output . setValue ( value ) ; } } setBooleanProperty ( component , "escape" , escape ) ; setProperty ( component , "style" , style ) ; setProperty ( component , "styleClass" , styleClass ) ; setProperty ( component , "title" , title ) ; } public void recycle ( ) { super . recycle ( ) ; converter = null ; value = null ; escape = null ; style = null ; styleClass = null ; title = null ; } }